args.sparql:
SELECT ?genreLabel WHERE {
  ?work wdt:P31 wd:Q571;
  rdfs:label ?title;
  wdt:P136 ?genre.
  FILTER (LANG(?title) = "en")
  FILTER (regex(STR(?title), "Goodbye[ ,]*\s*Mr[.]?\s*Chips", "i"))
  ?genre rdfs:label ?genreLabel.
  FILTER (LANG(?genreLabel) = "en")
}

SELECT DISTINCT ?genreLabel WHERE {
  ?work wdt:P31 wd:Q571 ;
         wdt:P50 wd:Q133442 ;
         rdfs:label ?title ;
         wdt:P136 ?genre .
  FILTER (LANG(?title) = "en")
  FILTER (CONTAINS(LCASE(STR(?title)), "goodbye mr chips"))
  ?genre rdfs:label ?genreLabel .
  FILTER (LANG(?genreLabel) = "en")
}

